const location = global.get('config')?.location;
const userAgent = global.get('config')?.system?.http?.user_agent;

msg.url = `https://api.weather.gov/points/${location.latitude},${location.longitude}`;
msg.headers = {
    'Accept': 'application/geo+json',
    'User-Agent': userAgent
};
msg.payload = '';

return msg;

const formatStatus = global.get('utils.formatStatus', 'initializers') || (t => t);

if (msg.statusCode !== 200) {
    node.error(`Points fetch failed: ${msg.statusCode}`, msg);
    return null;
}

const forecastUrl = msg.payload?.properties?.forecast;
if (!forecastUrl) {
    node.error('No forecast URL in points response', msg);
    return null;
}

flow.set('forecast_url', forecastUrl);
node.status({ fill: 'green', shape: 'dot', text: formatStatus(`URL resolved: ${forecastUrl}`) });
return null;

const forecastUrl = flow.get('forecast_url');
const userAgent = global.get('config')?.system?.http?.user_agent;

if (!forecastUrl) {
    node.status({ fill: 'yellow', shape: 'ring', text: 'Waiting for forecast URL...' });
    return null;
}

msg.url = forecastUrl;
msg.headers = {
    'Accept': 'application/geo+json',
    'User-Agent': userAgent
};
msg.payload = '';
return msg;

const formatStatus = global.get('utils.formatStatus', 'initializers') || (t => t);
const location = global.get('config')?.location;
const timezone = location?.timezone || 'America/New_York';

if (msg.statusCode !== 200) {
    node.error(`Forecast fetch failed: ${msg.statusCode}`, msg);
    return null;
}

const periods = msg.payload?.properties?.periods;
if (!Array.isArray(periods) || periods.length === 0) {
    node.error('No periods in forecast response', msg);
    return null;
}

// Extract icon condition code from NWS icon URL
// e.g. https://api.weather.gov/icons/land/day/bkn/rain,20?size=medium → rain
function extractIconCode(iconUrl) {
    try {
        const path = new URL(iconUrl).pathname;
        // path like /icons/land/day/bkn or /icons/land/day/bkn/rain,20
        const parts = path.split('/').filter(Boolean);
        // parts[0]=icons, [1]=land, [2]=day|night, [3]=code1, [4]=code2 (optional)
        const codes = [];
        if (parts[3]) codes.push(parts[3].split(',')[0]);
        if (parts[4]) codes.push(parts[4].split(',')[0]);

        // Priority: precipitation/severe wins over cloud cover
        const priority = [
            'tornado','hurricane','tropical_storm','blizzard',
            'tsra','tsra_sct','tsra_hi',
            'snow','rain_snow','rain_sleet','snow_sleet','fzra','rain_fzra','snow_fzra','sleet',
            'rain','rain_showers','rain_showers_hi',
            'fog','smoke','dust','haze','hot','cold',
            'wind_ovc','wind_bkn','wind_sct','wind_few','wind_skc',
            'ovc','bkn','sct','few','skc'
        ];

        for (const p of priority) {
            if (codes.includes(p)) return p;
        }
        return codes[0] || 'skc';
    } catch {
        return 'skc';
    }
}

// Build date-keyed map
const forecastMap = {};

for (const period of periods) {
    // Derive local date from startTime
    const startDate = new Date(period.startTime);
    const localDate = startDate.toLocaleDateString('en-CA', { timeZone: timezone }); // YYYY-MM-DD

    if (!forecastMap[localDate]) {
        forecastMap[localDate] = {};
    }

    const slot = period.isDaytime ? 'daytime' : 'overnight';

    // Don't overwrite if we already have this slot (first one wins)
    if (forecastMap[localDate][slot]) continue;

    forecastMap[localDate][slot] = {
        temperature: period.temperature,
        shortForecast: period.shortForecast,
        detailedForecast: period.detailedForecast,
        precipChance: period.probabilityOfPrecipitation?.value ?? 0,
        windSpeed: period.windSpeed,
        windDirection: period.windDirection,
        icon: extractIconCode(period.icon),
        isDaytime: period.isDaytime
    };
}

node.status({
    fill: 'green',
    shape: 'dot',
    text: formatStatus(`${Object.keys(forecastMap).length} day(s) normalized`)
});

msg.forecastMap = forecastMap;
return msg;

const formatStatus = global.get('utils.formatStatus', 'initializers') || (t => t);
const forecastUrl = flow.get('forecast_url');

msg.topic = 'highland/state/weather/forecast';
msg.retain = true;
msg.qos = 1;
msg.payload = JSON.stringify({
    timestamp: new Date().toISOString(),
    source: 'nws',
    forecast_url: forecastUrl,
    periods: msg.forecastMap
});

node.status({
    fill: 'green',
    shape: 'dot',
    text: formatStatus(`Snapshot published: ${Object.keys(msg.forecastMap).length} day(s)`)
});

return msg;
